    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Ovulation Peak Performance - 2w 3x/wk',
    'menstrual_cycle',
    3,
    60,
    ARRAY['Improve athletic performance', 'Develop explosiveness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Ovulation Peak Performance'
ON CONFLICT DO NOTHING;

